-- TrueSouth FMS — Legacy FlightTable import — PART 1 of 10 (1584 rows)
-- Single statement, NO temp table (works with the Supabase editor's pooled connections).
-- Any order; safe to re-run. Needs ts_flight_records to exist.
-- After the last part:  select count(*) from ts_flight_records where id like 'fr_imp_%';
-- Undo all:  delete from ts_flight_records where id like 'fr_imp_%';

insert into ts_flight_records
 (id,user_id,fr_date,aircraft,product,route_from,route_to,pob,off_blocks,on_blocks,actype,
  start_hours,end_hours,flight_time,tacho,landings,starts,done,submitted,manual,pic_name,details,note)
select v.id,
   coalesce(case when v.is_cur then (select u.id from ts_users u where u.name=v.pic limit 1) end, v.placeholder),
   v.fr_date::date, v.aircraft, v.product, v.route_from, v.route_to, v.pob::int, v.off_blocks, v.on_blocks, v.actype,
   v.start_hours::numeric, v.end_hours::numeric, v.flight_time::numeric, v.flight_time::numeric, coalesce(v.landings::int,1),
   1, true, true, true, v.pic, v.details, v.note
